import {
  Injectable,
  ConflictException,
  ForbiddenException,
  NotFoundException,
  UnauthorizedException,
} from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import * as crypto from 'crypto';
import { NocoDBService } from '../nocodb/nocodb.service';
import { NocoDBV3Service } from '../nocodb/nocodb-v3.service';
import { BootstrapAdminDto } from './dto/bootstrap-admin.dto';

interface NocoTableRef {
  id: string;
}

interface NocoUserRecord {
  id?: number | string;
  Id?: number | string;
  Username?: string;
}

interface NocoRoleRecord {
  id?: number | string;
  Id?: number | string;
}

@Injectable()
export class BootstrapAdminService {
  constructor(
    private readonly configService: ConfigService,
    private readonly nocoDBService: NocoDBService,
    private readonly nocoDBV3Service: NocoDBV3Service,
  ) {}

  async bootstrapAdmin(
    dto: BootstrapAdminDto,
    bootstrapToken: string | undefined,
  ): Promise<{
    success: true;
    userId: number;
    username: string;
    created: boolean;
  }> {
    this.assertBootstrapAllowed(bootstrapToken);

    const usersTable = this.assertTableRef(
      await this.nocoDBService.getTableByName('users'),
    );
    const rolesTable = this.assertTableRef(
      await this.nocoDBService.getTableByName('roles'),
    );
    const userRolesTable = this.assertTableRef(
      await this.nocoDBService.getTableByName('user_roles'),
    );

    const existingByUsername = this.asUserRecord(
      await this.nocoDBV3Service.findOne(
        usersTable.id,
        `(Username,eq,${dto.username})`,
      ),
    );

    const existingByEmail = this.asUserRecord(
      await this.nocoDBV3Service.findOne(
        usersTable.id,
        `(Email,eq,${dto.email})`,
      ),
    );

    if (
      existingByEmail &&
      !existingByUsername &&
      String(existingByEmail.Username ?? '') !== dto.username
    ) {
      throw new ConflictException(
        `User with email "${dto.email}" already exists`,
      );
    }

    const adminRole = this.asRoleRecord(
      await this.nocoDBV3Service.findOne(rolesTable.id, '(Role Name,eq,admin)'),
    );

    if (!adminRole) {
      throw new NotFoundException('Admin role is missing');
    }

    const adminRoleId = this.extractNumericId(adminRole);

    if (existingByUsername) {
      const existingUserId = this.extractNumericId(existingByUsername);
      const existingAssignment = await this.nocoDBV3Service.findOne(
        userRolesTable.id,
        `(User Id,eq,${existingUserId})~and(Role Id,eq,${adminRoleId})`,
      );

      if (!existingAssignment) {
        await this.nocoDBV3Service.create(userRolesTable.id, {
          'User Id': existingUserId,
          'Role Id': adminRoleId,
          'Assigned At': new Date().toISOString(),
        });
      }

      return {
        success: true,
        userId: existingUserId,
        username: dto.username,
        created: false,
      };
    }

    const passwordHash = this.hashPassword(dto.password);

    const createdUser = this.asUserRecord(
      await this.nocoDBV3Service.create(usersTable.id, {
        Username: dto.username,
        Email: dto.email,
        'Password Hash': passwordHash,
        'Is Active': true,
      }),
    );

    if (!createdUser) {
      throw new NotFoundException('Created user payload is invalid');
    }

    const userId = this.extractNumericId(createdUser);

    await this.nocoDBV3Service.create(userRolesTable.id, {
      'User Id': userId,
      'Role Id': adminRoleId,
      'Assigned At': new Date().toISOString(),
    });

    return {
      success: true,
      userId,
      username: dto.username,
      created: true,
    };
  }

  private assertBootstrapAllowed(bootstrapToken: string | undefined): void {
    const configuredToken = this.configService.get<string>(
      'BOOTSTRAP_ADMIN_TOKEN',
    );

    if (!configuredToken) {
      throw new ForbiddenException('Bootstrap token is not configured');
    }

    if (!bootstrapToken) {
      throw new UnauthorizedException('Missing bootstrap token');
    }

    const provided = Buffer.from(bootstrapToken);
    const expected = Buffer.from(configuredToken);

    if (provided.length !== expected.length) {
      throw new UnauthorizedException('Invalid bootstrap token');
    }

    const valid = crypto.timingSafeEqual(provided, expected);

    if (!valid) {
      throw new UnauthorizedException('Invalid bootstrap token');
    }
  }

  private hashPassword(password: string): string {
    const salt = crypto.randomBytes(16).toString('hex');
    const derivedKey = crypto.scryptSync(password, salt, 64).toString('hex');
    return `scrypt:${salt}:${derivedKey}`;
  }

  private assertTableRef(value: unknown): NocoTableRef {
    if (!value || typeof value !== 'object') {
      throw new NotFoundException(
        'Required bootstrap tables are missing. Run database initialization first.',
      );
    }

    const record = value as { id?: unknown };

    if (typeof record.id !== 'string') {
      throw new NotFoundException(
        'Required bootstrap tables are missing. Run database initialization first.',
      );
    }

    return { id: record.id };
  }

  private asUserRecord(value: unknown): NocoUserRecord | null {
    if (!value || typeof value !== 'object') {
      return null;
    }

    return value as NocoUserRecord;
  }

  private asRoleRecord(value: unknown): NocoRoleRecord | null {
    if (!value || typeof value !== 'object') {
      return null;
    }

    return value as NocoRoleRecord;
  }

  private extractNumericId(record: {
    id?: number | string;
    Id?: number | string;
  }): number {
    const rawId = record.id ?? record.Id;

    if (typeof rawId === 'number') {
      return rawId;
    }

    if (typeof rawId === 'string' && rawId.length > 0) {
      const parsed = Number(rawId);
      if (!Number.isNaN(parsed)) {
        return parsed;
      }
    }

    throw new NotFoundException('Invalid record ID payload');
  }
}

import { NestFactory } from '@nestjs/core';
import { AppModule } from './app.module';
import { NocoDBService } from './nocodb/nocodb.service';
import { Logger } from '@nestjs/common';

async function bootstrap() {
  const app = await NestFactory.createApplicationContext(AppModule);
  const nocoDBService = app.get(NocoDBService);
  const logger = new Logger('DebugColumns');

  try {
    const usersTable = await nocoDBService.getTableByName('users');
    if (!usersTable) {
      logger.error('Users table not found');
      return;
    }

    logger.log(`Users Table ID: ${usersTable.id}`);

    const httpClient = nocoDBService.getHttpClient();

    // Test filters
    const filters = ['(username,eq,admin)', '(Username,eq,admin)'];

    for (const filter of filters) {
      try {
        logger.log(`Testing filter: ${filter}`);
        const response = await httpClient.get(
          `/api/v2/tables/${usersTable.id}/records`,
          {
            params: { where: filter },
          },
        );
        logger.log(
          `Filter ${filter} success. Records: ${response.data.list.length}`,
        );
      } catch (err: any) {
        logger.error(
          `Filter ${filter} failed: ${err.response?.data?.msg || err.message}`,
        );
      }
    }

    /*
        // Fetch records to see actual column names
        try {
            const recordsResponse = await httpClient.get(`/api/v2/tables/${usersTable.id}/records`, {
                params: { limit: 1 }
            });

            logger.log('Records found: ' + recordsResponse.data.list.length);
            if (recordsResponse.data.list.length > 0) {
                const record = recordsResponse.data.list[0];
                logger.log('Record Keys:', Object.keys(record));
                logger.log('Record Data:', JSON.stringify(record, null, 2));
            } else {
                logger.log('No records found in table.');
            }
        } catch (recordError) {
            logger.error('Error fetching records', recordError);
        }
        */
  } catch (error) {
    logger.error('Error fetching columns', error);
  } finally {
    await app.close();
  }
}

bootstrap();

import { NestFactory } from '@nestjs/core';
import { AppModule } from './app.module';
import { NocoDBService } from './nocodb/nocodb.service';
import { Logger } from '@nestjs/common';

async function bootstrap() {
  const app = await NestFactory.createApplicationContext(AppModule);
  const nocoDBService = app.get(NocoDBService);
  const logger = new Logger('DeleteTables');

  try {
    const httpClient = nocoDBService.getHttpClient();
    const baseId = nocoDBService.getBaseId();

    // Tables to delete
    const tablesToDelete = ['user_roles', 'table_permissions'];

    for (const tableName of tablesToDelete) {
      try {
        const table = await nocoDBService.getTableByName(tableName);

        if (!table) {
          logger.warn(`Table ${tableName} not found, skipping...`);
          continue;
        }

        logger.log(`Deleting table ${tableName} (ID: ${table.id})...`);

        await httpClient.delete(`/api/v2/meta/tables/${table.id}`);

        logger.log(`✓ Table ${tableName} deleted successfully`);
      } catch (error: any) {
        logger.error(
          `Failed to delete table ${tableName}:`,
          error.response?.data || error.message,
        );
      }
    }

    logger.log('Done!');
  } catch (error) {
    logger.error('Error during table deletion', error);
  } finally {
    await app.close();
  }
}

bootstrap();

import { NestFactory } from '@nestjs/core';
import { AppModule } from './app.module';
import { NocoDBExceptionFilter } from './nocodb/filters/nocodb-exception.filter';
import { ValidationPipe } from '@nestjs/common';
import { DocumentBuilder, SwaggerModule } from '@nestjs/swagger';
import {
  WinstonModule,
  utilities as nestWinstonModuleUtilities,
} from 'nest-winston';
import * as winston from 'winston';
import * as path from 'path';

async function bootstrap() {
  const logDir = process.env.LOG_DIR || path.join(process.cwd(), 'logs');

  // Create logger with Console and File transports
  const logger = WinstonModule.createLogger({
    transports: [
      new winston.transports.Console({
        format: winston.format.combine(
          winston.format.timestamp(),
          winston.format.ms(),
          nestWinstonModuleUtilities.format.nestLike('NocoDBMiddleware', {
            colors: true,
            prettyPrint: true,
          }),
        ),
      }),
      new winston.transports.File({
        dirname: logDir,
        filename: 'error.log',
        level: 'error',
        format: winston.format.combine(
          winston.format.timestamp(),
          winston.format.json(),
        ),
      }),
      new winston.transports.File({
        dirname: logDir,
        filename: 'combined.log',
        format: winston.format.combine(
          winston.format.timestamp(),
          winston.format.json(),
        ),
      }),
    ],
  });

  const app = await NestFactory.create(AppModule, {
    logger: logger,
  });

  // Global filters
  app.useGlobalFilters(new NocoDBExceptionFilter());

  // Global validation pipe
  app.useGlobalPipes(
    new ValidationPipe({
      whitelist: true,
      forbidNonWhitelisted: true,
      transform: true,
    }),
  );

  // Swagger setup
  const config = new DocumentBuilder()
    .setTitle('NocoDB Middleware API')
    .setDescription('API documentation for NocoDB Middleware')
    .setVersion('1.0')
    .addBearerAuth()
    .build();
  const document = SwaggerModule.createDocument(app, config);
  SwaggerModule.setup('api', app, document);

  // Enable CORS with configurable allowlist
  const corsOrigins = (process.env.CORS_ORIGINS || '')
    .split(',')
    .map((origin) => origin.trim())
    .filter(Boolean);

  if (corsOrigins.length === 0) {
    logger.warn('CORS_ORIGINS not set. Applying restrictive CORS policy.');
    app.enableCors({
      origin: false,
      methods: ['GET', 'POST', 'PUT', 'PATCH', 'DELETE', 'OPTIONS'],
      allowedHeaders: [
        'Content-Type',
        'Authorization',
        'X-Requested-With',
        'x-request-id',
      ],
      credentials: false,
    });
  } else {
    app.enableCors({
      origin: corsOrigins,
      methods: ['GET', 'POST', 'PUT', 'PATCH', 'DELETE', 'OPTIONS'],
      allowedHeaders: [
        'Content-Type',
        'Authorization',
        'X-Requested-With',
        'x-request-id',
      ],
      credentials: true,
    });
  }

  // Enable graceful shutdown
  app.enableShutdownHooks();

  await app.listen(process.env.PORT ?? 3000);
  logger.log(`Application is running on: ${await app.getUrl()}`);
}
bootstrap();

import { Test, TestingModule } from '@nestjs/testing';
import { CACHE_MANAGER } from '@nestjs/cache-manager';
import { NocoDBCacheService } from './nocodb-cache.service';

describe('NocoDBCacheService', () => {
  let service: NocoDBCacheService;
  let cacheManager: any;

  beforeEach(async () => {
    const mockCacheManager = {
      get: jest.fn(),
      set: jest.fn(),
      del: jest.fn(),
    };

    const module: TestingModule = await Test.createTestingModule({
      providers: [
        NocoDBCacheService,
        {
          provide: CACHE_MANAGER,
          useValue: mockCacheManager,
        },
      ],
    }).compile();

    service = module.get<NocoDBCacheService>(NocoDBCacheService);
    cacheManager = module.get(CACHE_MANAGER);
  });

  it('should be defined', () => {
    expect(service).toBeDefined();
  });

  describe('get', () => {
    it('should get value from cache', async () => {
      const key = 'test-key';
      const value = { data: 'test' };

      cacheManager.get.mockResolvedValue(value);

      const result = await service.get(key);

      expect(cacheManager.get).toHaveBeenCalledWith(key);
      expect(result).toEqual(value);
    });
  });

  describe('set', () => {
    it('should set value in cache', async () => {
      const key = 'test-key';
      const value = { data: 'test' };
      const ttl = 60000;

      await service.set(key, value, ttl);

      expect(cacheManager.set).toHaveBeenCalledWith(key, value, ttl);
    });
  });

  describe('generateKey', () => {
    it('should generate cache key from prefix and params', () => {
      const prefix = 'test';
      const params = { id: 1, name: 'example' };

      const key = service.generateKey(prefix, params);

      expect(key).toBe('test:{"id":1,"name":"example"}');
    });
  });
});

import { Test, TestingModule } from '@nestjs/testing';
import { Logger } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { DatabaseInitializationService } from './database-initialization.service';
import { NocoDBService } from './nocodb.service';
import { NocoDBV3Service } from './nocodb-v3.service';

describe('DatabaseInitializationService', () => {
  let service: DatabaseInitializationService;
  let nocoDBService: NocoDBService;
  let nocoDBV3Service: NocoDBV3Service;
  let mockHttpClient: any;

  beforeEach(async () => {
    mockHttpClient = {
      get: jest.fn(),
      post: jest.fn(),
    };

    const module: TestingModule = await Test.createTestingModule({
      providers: [
        DatabaseInitializationService,
        {
          provide: NocoDBService,
          useValue: {
            getTablePrefix: jest.fn().mockReturnValue('nc_'),
            getTableByName: jest.fn(),
            getHttpClient: jest.fn().mockReturnValue(mockHttpClient),
            getBaseId: jest.fn().mockReturnValue('base_id'),
          },
        },
        {
          provide: NocoDBV3Service,
          useValue: {
            createTableV3: jest.fn(),
            findOne: jest.fn(),
            create: jest.fn(),
          },
        },
        {
          provide: ConfigService,
          useValue: {
            get: jest.fn(),
          },
        },
      ],
    }).compile();

    service = module.get<DatabaseInitializationService>(
      DatabaseInitializationService,
    );
    nocoDBService = module.get<NocoDBService>(NocoDBService);
    nocoDBV3Service = module.get<NocoDBV3Service>(NocoDBV3Service);

    jest.spyOn(Logger.prototype, 'log').mockImplementation(() => {});
    jest.spyOn(Logger.prototype, 'warn').mockImplementation(() => {});
    jest.spyOn(Logger.prototype, 'error').mockImplementation(() => {});
  });

  it('should be defined', () => {
    expect(service).toBeDefined();
  });

  it('onModuleInit should trigger table initialization', async () => {
    const initSpy = jest
      .spyOn(service as any, 'initializeTables')
      .mockResolvedValue(undefined);
    await service.onModuleInit();
    expect(initSpy).toHaveBeenCalled();
  });

  it('initializeTables should attempt base and junction tables and seeding', async () => {
    const ensureSpy = jest
      .spyOn(service as any, 'ensureTableExists')
      .mockResolvedValue('table-id');
    const seedPermSpy = jest
      .spyOn(service as any, 'seedDefaultPermissions')
      .mockResolvedValue(undefined);
    const seedUserSpy = jest
      .spyOn(service as any, 'seedDefaultUser')
      .mockResolvedValue(undefined);

    await (service as any).initializeTables();

    expect(ensureSpy).toHaveBeenCalledTimes(4);
    expect(seedPermSpy).toHaveBeenCalled();
    expect(seedUserSpy).toHaveBeenCalled();
  });

  it('ensureTableExists should return existing table id when accessible', async () => {
    (nocoDBService.getTableByName as jest.Mock).mockResolvedValue({
      id: 'existing-id',
    });
    mockHttpClient.get.mockResolvedValue({ data: { id: 'existing-id' } });

    const result = await (service as any).ensureTableExists({
      tableName: 'users',
      title: 'Users',
      columns: [
        { name: 'username', title: 'Username', type: 'SingleLineText' },
      ],
    });

    expect(result).toBe('existing-id');
    expect(nocoDBV3Service.createTableV3).not.toHaveBeenCalled();
  });

  it('ensureTableExists should create table via v3 when missing', async () => {
    (nocoDBService.getTableByName as jest.Mock).mockResolvedValue(null);
    (nocoDBV3Service.createTableV3 as jest.Mock).mockResolvedValue({
      id: 'new-id',
    });

    const result = await (service as any).ensureTableExists({
      tableName: 'users',
      title: 'Users',
      columns: [
        { name: 'username', title: 'Username', type: 'SingleLineText' },
      ],
    });

    expect(nocoDBV3Service.createTableV3).toHaveBeenCalledWith(
      'base_id',
      expect.objectContaining({
        table_name: 'nc_users',
        title: 'nc_users',
      }),
    );
    expect(result).toBe('new-id');
  });

  it('seedDefaultUser should skip when bootstrap admin username is missing', async () => {
    const configService = (service as any).configService;
    configService.get.mockReturnValue(undefined);

    await (service as any).seedDefaultUser();

    expect(nocoDBService.getTableByName).not.toHaveBeenCalled();
  });

  it('seedDefaultUser should assign admin role to configured bootstrap user', async () => {
    const configService = (service as any).configService;
    configService.get.mockReturnValue('bootstrap-admin');

    (nocoDBService.getTableByName as jest.Mock)
      .mockResolvedValueOnce({ id: 'users-id' })
      .mockResolvedValueOnce({ id: 'roles-id' })
      .mockResolvedValueOnce({ id: 'user-roles-id' });

    (nocoDBV3Service.findOne as jest.Mock)
      .mockResolvedValueOnce({ id: 10, Username: 'bootstrap-admin' })
      .mockResolvedValueOnce({ id: 1, 'Role Name': 'admin' })
      .mockResolvedValueOnce(null);

    await (service as any).seedDefaultUser();

    expect(nocoDBV3Service.create).toHaveBeenCalledWith('user-roles-id', {
      'User Id': 10,
      'Role Id': 1,
      'Assigned At': expect.any(String),
    });
  });
});

import { Injectable, Logger, OnModuleInit } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { NocoDBService } from './nocodb.service';
import { NocoDBV3Service } from './nocodb-v3.service';

interface ColumnDefinition {
  name: string;
  title: string;
  type: string;
  options?: any;
  parentId?: string; // For LinkToAnotherRecord
  pk?: boolean;
  ai?: boolean;
}

interface TableDefinition {
  tableName: string;
  title: string;
  columns: ColumnDefinition[];
}

@Injectable()
export class DatabaseInitializationService implements OnModuleInit {
  private readonly logger = new Logger(DatabaseInitializationService.name);

  constructor(
    private nocoDBService: NocoDBService,
    private nocoDBV3Service: NocoDBV3Service,
    private configService: ConfigService,
  ) {}

  async onModuleInit() {
    const prefix = this.nocoDBService.getTablePrefix();
    const prefixInfo = prefix ? ` with prefix "${prefix}"` : '';

    this.logger.log(`Starting database initialization${prefixInfo}...`);
    await this.initializeTables();
    this.logger.log('Database initialization completed');
  }

  private async initializeTables() {
    // 1. Create Base Tables (Users & Roles)
    const usersTableId = await this.ensureTableExists({
      tableName: 'users',
      title: 'Users',
      columns: [
        { name: 'username', title: 'Username', type: 'SingleLineText' },
        { name: 'email', title: 'Email', type: 'Email' },
        { name: 'password_hash', title: 'Password Hash', type: 'LongText' },
        { name: 'is_active', title: 'Is Active', type: 'Checkbox' },
      ],
    });

    const rolesTableId = await this.ensureTableExists({
      tableName: 'roles',
      title: 'Roles',
      columns: [
        { name: 'role_name', title: 'Role Name', type: 'SingleLineText' },
        { name: 'description', title: 'Description', type: 'LongText' },
        { name: 'is_system_role', title: 'Is System Role', type: 'Checkbox' },
      ],
    });

    if (!usersTableId || !rolesTableId) {
      this.logger.error(
        'Failed to initialize base tables. Skipping junction tables.',
      );
      return;
    }

    // 2. Create Junction Tables with stable Foreign Key numbers (Avoids NocoDB Meta Corruption)
    await this.ensureTableExists({
      tableName: 'user_roles',
      title: 'User Roles',
      columns: [
        { name: 'user_id', title: 'User Id', type: 'Number' },
        { name: 'role_id', title: 'Role Id', type: 'Number' },
        { name: 'assigned_at', title: 'Assigned At', type: 'DateTime' },
      ],
    });

    await this.ensureTableExists({
      tableName: 'table_permissions',
      title: 'Table Permissions',
      columns: [
        { name: 'role_id', title: 'Role Id', type: 'Number' },
        { name: 'table_name', title: 'Table Name', type: 'SingleLineText' },
        { name: 'can_create', title: 'Can Create', type: 'Checkbox' },
        { name: 'can_read', title: 'Can Read', type: 'Checkbox' },
        { name: 'can_update', title: 'Can Update', type: 'Checkbox' },
        { name: 'can_delete', title: 'Can Delete', type: 'Checkbox' },
      ],
    });

    // 3. Seed default data
    await this.seedDefaultPermissions();
    await this.seedDefaultUser();
  }

  /**
   * Ensure a relationship link exists between tables
   * Uses V2 Meta API which is currently more stable for building relationships in V3 bases
   */
  private async ensureLinkExists(
    sourceTableId: string,
    name: string,
    title: string,
    targetTableId: string,
  ) {
    const maxRetries = 3;
    let lastError: any;

    for (let i = 1; i <= maxRetries; i++) {
      try {
        const httpClient = this.nocoDBService.getHttpClient();

        // Wait a bit before checking/creating (especially on retry)
        // This gives NocoDB time to finalize previous metadata operations
        if (i > 1) {
          this.logger.log(`Retry ${i}/${maxRetries} for link ${name} in 2s...`);
          await new Promise((resolve) => setTimeout(resolve, 2000));
        }

        const schema = await httpClient.get(
          `/api/v2/meta/tables/${sourceTableId}`,
        );
        const columns = schema.data.columns || [];
        const exists = columns.some(
          (c: any) => c.column_name === name || c.title === title,
        );

        if (exists) {
          this.logger.log(`✓ Link ${name} already exists`);
          return;
        }

        this.logger.log(
          `Creating link ${name} -> ${targetTableId} (Attempt ${i})...`,
        );

        const payload = {
          column_name: name,
          title: title,
          uidt: 'LinkToAnotherRecord',
          type: 'LinkToAnotherRecord',
          parentId: sourceTableId,
          childId: targetTableId,
          type_options: {
            type: 'bt', // Belongs To relationship
          },
        };

        await httpClient.post(
          `/api/v2/meta/tables/${sourceTableId}/columns`,
          payload,
        );
        this.logger.log(`Link column ${name} created successfully`);
        return;
      } catch (error) {
        lastError = error;
        this.logger.warn(
          `Attempt ${i} failed for link ${name}: ${JSON.stringify(error.response?.data || error.message)}`,
        );
      }
    }

    this.logger.error(
      `Failed to ensure link ${name} after ${maxRetries} attempts:`,
      JSON.stringify(lastError?.response?.data || lastError?.message, null, 2),
    );
  }

  private async ensureTableExists(
    tableDef: TableDefinition,
  ): Promise<string | null> {
    const prefix = this.nocoDBService.getTablePrefix();
    const fullTableName = `${prefix}${tableDef.tableName}`;

    // Check if table exists
    let existingTable = await this.nocoDBService.getTableByName(
      tableDef.tableName,
    );

    // Resilience: If we find a table but can't read its details, it's likely corrupted
    // (like the 'getModel' error). In that case, we should proceed as if it doesn't exist.
    if (existingTable) {
      try {
        const httpClient = this.nocoDBService.getHttpClient();
        await httpClient.get(`/api/v2/meta/tables/${existingTable.id}`);
        this.logger.log(
          `Table ${fullTableName} already exists (ID: ${existingTable.id})`,
        );
        return existingTable.id;
      } catch (e) {
        this.logger.warn(
          `Existing table ${fullTableName} (${existingTable.id}) found but inaccessible. Ignoring it.`,
        );
        existingTable = null;
      }
    }

    this.logger.log(`Creating table ${fullTableName} using V3 API...`);

    try {
      const baseId = this.nocoDBService.getBaseId();

      const fields = tableDef.columns.map((col) => ({
        column_name: col.name,
        title: col.title,
        uidt: col.type,
        type: col.type,
      }));

      const response = await this.nocoDBV3Service.createTableV3(baseId, {
        table_name: fullTableName,
        title: fullTableName,
        fields: fields,
      });

      const tableId = response.id || response.Id;
      this.logger.log(`Table ${fullTableName} created (ID: ${tableId})`);

      return tableId;
    } catch (error) {
      this.logger.error(
        `Failed to create table ${fullTableName}`,
        error.response?.data || error.message,
      );
      return null;
    }
  }

  private async seedDefaultPermissions() {
    this.logger.log('Seeding default permissions...');
    try {
      const rolesTable = await this.nocoDBService.getTableByName('roles');
      const permissionsTable =
        await this.nocoDBService.getTableByName('table_permissions');

      if (!rolesTable || !permissionsTable) {
        this.logger.warn(
          'Roles or Permissions table not found. Skipping seeding.',
        );
        return;
      }

      // 1. Get or Create Admin Role
      const adminRole = await this.nocoDBV3Service.findOne(
        rolesTable.id,
        '(Role Name,eq,admin)',
      );
      let adminRoleId;

      if (!adminRole) {
        this.logger.log('Creating default admin role...');
        const newRole = await this.nocoDBV3Service.create(rolesTable.id, {
          'Role Name': 'admin',
          Description: 'System Administrator',
          'Is System Role': true,
        });
        adminRoleId = newRole.id || newRole.Id;
      } else {
        adminRoleId = adminRole.id || adminRole.Id;
      }

      // 2. Check if admin permissions exist
      // Use 'Role Id' for V3 Data API filtering
      const existingPerms = await this.nocoDBV3Service.findOne(
        permissionsTable.id,
        `(Role Id,eq,${adminRoleId})~and(Table Name,eq,users)`,
      );

      if (!existingPerms) {
        this.logger.log('Creating admin permissions for users table...');
        await this.nocoDBV3Service.create(permissionsTable.id, {
          'Table Name': 'users',
          'Can Create': true,
          'Can Read': true,
          'Can Update': true,
          'Can Delete': true,
          'Role Id': adminRoleId,
        });
      }

      this.logger.log('Default permissions seeded successfully');
    } catch (error) {
      this.logger.error('Failed to seed default permissions', error);
    }
  }

  private async seedDefaultUser() {
    this.logger.log('Seeding default user...');
    try {
      const bootstrapAdminUsername = this.configService.get<string>(
        'NOCODB_BOOTSTRAP_ADMIN_USERNAME',
      );

      if (!bootstrapAdminUsername) {
        this.logger.warn(
          'NOCODB_BOOTSTRAP_ADMIN_USERNAME not configured. Skipping default admin assignment.',
        );
        return;
      }

      const usersTable = await this.nocoDBService.getTableByName('users');
      const rolesTable = await this.nocoDBService.getTableByName('roles');
      const userRolesTable =
        await this.nocoDBService.getTableByName('user_roles');

      if (!usersTable || !rolesTable || !userRolesTable) {
        this.logger.warn('Required tables not found. Skipping user seeding.');
        return;
      }

      // 1. Find existing bootstrap admin user
      const adminUser = await this.nocoDBV3Service.findOne(
        usersTable.id,
        `(Username,eq,${bootstrapAdminUsername})`,
      );

      if (!adminUser) {
        this.logger.warn(
          `Bootstrap admin user "${bootstrapAdminUsername}" not found. Skipping admin role assignment.`,
        );
        return;
      }

      const userId = adminUser.id || adminUser.Id;

      // 2. Get Admin Role
      const adminRole = await this.nocoDBV3Service.findOne(
        rolesTable.id,
        '(Role Name,eq,admin)',
      );
      if (!adminRole) {
        this.logger.warn('Admin role not found. Cannot assign role to user.');
        return;
      }
      const adminRoleId = adminRole.id || adminRole.Id;

      // 3. Check and Assign Role
      const existingUserRole = await this.nocoDBV3Service.findOne(
        userRolesTable.id,
        `(User Id,eq,${userId})~and(Role Id,eq,${adminRoleId})`,
      );

      if (!existingUserRole) {
        this.logger.log('Assigning admin role to bootstrap admin user...');
        await this.nocoDBV3Service.create(userRolesTable.id, {
          'User Id': userId,
          'Role Id': adminRoleId,
          'Assigned At': new Date().toISOString(),
        });
        this.logger.log('Admin role assigned successfully');
      } else {
        this.logger.log('Bootstrap admin user already has admin role');
      }
    } catch (error) {
      this.logger.error('Failed to seed default user', error);
    }
  }

  private delay(ms: number): Promise<void> {
    return new Promise((resolve) => setTimeout(resolve, ms));
  }
}

import {
  ExceptionFilter,
  Catch,
  ArgumentsHost,
  HttpException,
  Logger,
} from '@nestjs/common';
import { Request, Response } from 'express';
import { NocoDBException } from '../exceptions/nocodb.exception';

@Catch(HttpException)
export class NocoDBExceptionFilter implements ExceptionFilter {
  private readonly logger = new Logger(NocoDBExceptionFilter.name);

  catch(exception: HttpException, host: ArgumentsHost) {
    const ctx = host.switchToHttp();
    const response = ctx.getResponse<Response>();
    const request = ctx.getRequest<Request>();
    const status = exception.getStatus();
    const exceptionResponse = exception.getResponse();

    const errorResponse = {
      statusCode: status,
      timestamp: new Date().toISOString(),
      path: request.url,
      message: (exceptionResponse as any).message || exception.message,
      error: (exceptionResponse as any).error || 'Internal Server Error',
    };

    // Skip logging for 404 errors on static assets
    const isStaticAsset404 =
      status === 404 &&
      (request.url.includes('/favicon.ico') ||
        request.url.includes('.ico') ||
        request.url.includes('.png') ||
        request.url.includes('.jpg') ||
        request.url.includes('.svg'));

    if (!isStaticAsset404) {
      if (exception instanceof NocoDBException) {
        this.logger.warn(`NocoDB Exception: ${JSON.stringify(errorResponse)}`);
      } else {
        this.logger.error(
          `Http Exception: ${JSON.stringify(errorResponse)}`,
          exception.stack,
        );
      }
    }

    response.status(status).json(errorResponse);
  }
}

import {
  Injectable,
  NestInterceptor,
  ExecutionContext,
  CallHandler,
  Logger,
} from '@nestjs/common';
import { Observable, of } from 'rxjs';
import { mergeMap } from 'rxjs/operators';
import { NocoDBCacheService } from '../cache/nocodb-cache.service';

@Injectable()
export class CacheInterceptor implements NestInterceptor {
  private readonly logger = new Logger(CacheInterceptor.name);

  constructor(private readonly cacheService: NocoDBCacheService) {}

  async intercept(
    context: ExecutionContext,
    next: CallHandler,
  ): Promise<Observable<any>> {
    const request = context.switchToHttp().getRequest();

    // Only cache GET requests
    if (request.method !== 'GET') {
      return next.handle();
    }

    const key = `route:${request.url}`;
    const cachedResponse = await this.cacheService.get(key);

    if (cachedResponse) {
      this.logger.log(`Cache hit for ${key}`);
      return of(cachedResponse);
    }

    return next.handle().pipe(
      mergeMap(async (response) => {
        this.logger.log(`Cache miss for ${key}, caching response`);
        await this.cacheService.set(key, response, 60 * 1000); // Default TTL 60s
        return response;
      }),
    );
  }
}

import { Injectable, NestMiddleware } from '@nestjs/common';
import { Request, Response, NextFunction } from 'express';
import * as crypto from 'crypto';

@Injectable()
export class NocoDbContextMiddleware implements NestMiddleware {
  use(req: Request, res: Response, next: NextFunction) {
    // Assuming JwtAuthGuard has already run and attached user to req.user
    // If not, we might need to handle that or this middleware should run after Auth
    const user = (req as any).user;

    if (user) {
      // Set NocoDB specific headers or context based on user
      req.headers['x-nocodb-user-id'] = user.userId;
      req.headers['x-nocodb-user-roles'] = user.roles
        ? user.roles.join(',')
        : '';
    }

    // Generate a Request ID for tracing if not present
    if (!req.headers['x-request-id']) {
      req.headers['x-request-id'] = crypto.randomUUID();
    }

    next();
  }
}

